<template><AdminPage title="影片管理" kicker="Content Ops" hint="维护本地片库、上下架状态与影片关联信息。"><template #actions><el-input v-model="query.keyword" clearable placeholder="片名 / TMDB ID" @keyup.enter="search"/><el-select v-model="query.status" clearable placeholder="全部状态"><el-option label="上架" :value="1"/><el-option label="下架" :value="0"/></el-select><button class="pill-button" @click="search">查询</button><button class="pill-button is-active" @click="openCreate">新增影片</button></template><div class="surface-card table-shell overflow-hidden p-4"><el-table :data="records" v-loading="loading" @selection-change="selected=$event"><el-table-column type="selection" width="48"/><el-table-column label="影片" min-width="240"><template #default="{row}"><div class="admin-movie-cell"><img v-if="row.posterUrl" :src="row.posterUrl"/><div><b>{{row.title}}</b><p>{{row.categories||'未分类'}} · {{row.region||'地区未知'}}</p></div></div></template></el-table-column><el-table-column prop="directors" label="导演" min-width="150"/><el-table-column prop="averageRating" label="评分" width="80"/><el-table-column label="热度" width="130"><template #default="{row}">藏 {{row.favoriteCount}} · 看 {{row.viewCount}}</template></el-table-column><el-table-column label="状态" width="100"><template #default="{row}"><el-switch :model-value="row.status===1" @change="toggle(row,$event)"/></template></el-table-column><el-table-column label="操作" width="140"><template #default="{row}"><el-button link @click="edit(row)">编辑</el-button><el-button link type="danger" @click="remove(row)">删除</el-button></template></el-table-column></el-table><div class="admin-table-foot"><el-button :disabled="!selected.length" type="danger" plain @click="batchRemove">批量删除</el-button><AdminPagination v-model:page="query.pageNum" :total="total" @change="load"/></div></div><el-dialog v-model="dialog" :title="form.id?'编辑影片':'新增影片'" width="min(720px,92vw)"><el-form label-position="top"><div class="admin-form-grid"><el-form-item label="影片标题" required><el-input v-model="form.title"/></el-form-item><el-form-item label="原标题"><el-input v-model="form.originalTitle"/></el-form-item><el-form-item label="地区"><el-input v-model="form.region"/></el-form-item><el-form-item label="语言"><el-input v-model="form.language"/></el-form-item><el-form-item label="上映日期"><el-date-picker v-model="form.releaseDate" type="date" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="时长（分钟）"><el-input-number v-model="form.runtime" :min="0"/></el-form-item><el-form-item label="评分"><el-input-number v-model="form.averageRating" :min="0" :max="10" :step="0.1"/></el-form-item><el-form-item label="状态"><el-radio-group v-model="form.status"><el-radio-button :value="1">上架</el-radio-button><el-radio-button :value="0">下架</el-radio-button></el-radio-group></el-form-item></div><el-form-item label="海报地址"><el-input v-model="form.posterUrl"/></el-form-item><el-form-item label="背景图地址"><el-input v-model="form.backdropUrl"/></el-form-item><el-form-item label="影片简介"><el-input v-model="form.overview" type="textarea" :rows="4" maxlength="1000" show-word-limit/></el-form-item></el-form><template #footer><button class="pill-button" @click="dialog=false">取消</button><button class="pill-button is-active" :disabled="saving" @click="submit">保存</button></template></el-dialog></AdminPage></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{pageAdminMovies,getAdminMovie,saveAdminMovie,setMovieStatus,deleteAdminMovie,batchDeleteMovies}from'@/api/adminManagement';import AdminPage from'@/components/admin/AdminPage.vue';import AdminPagination from'@/components/admin/AdminPagination.vue';const records=ref([]),total=ref(0),loading=ref(false),dialog=ref(false),saving=ref(false),selected=ref([]),query=reactive({keyword:'',status:null,pageNum:1,pageSize:10});const blank=()=>({id:null,title:'',originalTitle:'',overview:'',posterUrl:'',backdropUrl:'',releaseDate:null,runtime:null,region:'',language:'',averageRating:0,status:1,categoryIds:[],tagIds:[],actorIds:[],directorIds:[]});const form=reactive(blank());async function load(){loading.value=true;try{const r=await pageAdminMovies(query);records.value=r.data.records;total.value=r.data.total}finally{loading.value=false}}function search(){query.pageNum=1;load()}function openCreate(){Object.assign(form,blank());dialog.value=true}async function edit(row){Object.assign(form,blank(),(await getAdminMovie(row.id)).data);dialog.value=true}async function submit(){if(!form.title)return ElMessage.warning('请填写影片标题');saving.value=true;try{await saveAdminMovie(form.id,form);ElMessage.success('影片已保存');dialog.value=false;load()}finally{saving.value=false}}async function toggle(row,v){await setMovieStatus(row.id,v?1:0);row.status=v?1:0;ElMessage.success('状态已更新')}async function remove(row){await ElMessageBox.confirm(`确认删除《${row.title}》？`,'删除影片',{type:'warning'});await deleteAdminMovie(row.id);load()}async function batchRemove(){await ElMessageBox.confirm(`确认删除选中的 ${selected.value.length} 部影片？`,'批量删除',{type:'warning'});await batchDeleteMovies(selected.value.map(v=>v.id));load()}onMounted(load)</script>
